metodos.codigoOriginal:
Select Emps, Dopes, Numes ;
  From csCabec ;
 Where Empty(Gerado) ;
  Into Cursor LocalGerado

lnFal = Reccount([LocalGerado])

If (lnFal > 0)
	If MessageBox([Existem ] + Alltrim(Str(lnFal, 10)) + [ Operaçőes Năo Confirmadas!] + Chr(13) + ;
				  [Tem Certeza Que Năo Deseja Gerar Esses Pedidos?], 4+32+256, [Atençăo!!!]) <> 6
		Return .f.
	Else
		fGravarLog([T], CrSigCdNec.Dopps, [AUTOMATICO], [A Geraçăo de ] + Alltrim(Str(lnFal, 10)) + ;
					 [ Operaçăo Foi Cancelada Sem Confirmaçăo])
	EndIf
En... [TRUNCADO]
